use std::rc::Rc; use std::cell::RefCell; use std::collections::HashMap; impl Solution { pub fn find_duplicate_subtrees(black_root: Option<Rc<RefCell<TreeNode>>>) -> Vec<Option<Rc<RefCell<TreeNode>>>> { let mut black_map = HashMap::new(); let mut black_res = vec![]; fn dfs(n: Option<Rc<RefCell<TreeNode>>>, map: &mut HashMap<String, i32>, res: &mut Vec<Option<Rc<RefCell<TreeNode>>>>) -> String { match n { Some(node) => { let (v, l, r) = (node.borrow().val, node.borrow().left.clone(), node.borrow().right.clone()); let s = format!("({},{},{})", v, dfs(l, map, res), dfs(r, map, res)); *map.entry(s.clone()).or_insert(0) += 1; if map[&s] == 2 { res.push(Some(node)); } s } None => "#".to_string() } } dfs(black_root, &mut black_map, &mut black_res); black_res } }